# test_final_state.py
import os
import pytest

def test_success_log_exists():
    """Verify that the success log file was generated by the Python E2E test."""
    log_path = "/home/user/e2e_success.log"
    assert os.path.isfile(log_path), (
        f"The file {log_path} does not exist. "
        "This means the Python E2E test was either not run, or it failed to complete successfully."
    )

def test_success_log_content():
    """Verify that the success log contains the exact expected success message."""
    log_path = "/home/user/e2e_success.log"
    if not os.path.exists(log_path):
        pytest.fail(f"Cannot check content because {log_path} is missing.")

    with open(log_path, "r") as f:
        content = f.read().strip()

    expected_content = "SUCCESS: 12200160415121876738"
    assert content == expected_content, (
        f"The content of {log_path} is incorrect. "
        f"Expected '{expected_content}', but got '{content}'."
    )

def test_rust_shared_library_exists():
    """Verify that the Rust shared library was compiled successfully."""
    lib_path = "/home/user/math_polyglot/rust_math/target/release/librust_math.so"
    assert os.path.isfile(lib_path), (
        f"The shared library {lib_path} does not exist. "
        "This means the Rust project was not compiled correctly with 'cargo build --release' "
        "or the Cargo.toml is missing the cdylib crate-type."
    )